import React from 'react';

const Hero = () => {
  return (
    <section id="top" className="section hero">
      <div className="container">
        <p className="eyebrow">Howdy! Meet your trusted design partner,</p>
        <h1 className="display">crafting strong brands for SaaS and Web3.</h1>
        <div className="hero-cta">
          <a className="btn btn-primary" href="#work">See work</a>
          <a className="btn" href="#contact">Connect</a>
        </div>
      </div>
    </section>
  );
};

export default Hero;
